function my_register_block() {
    register_block_type('my-plugin/hero', [
        'editor_script' => 'my-hero-editor',
        'render_callback' => 'render_hero_block',
    ]);
}
add_action('init', 'my_register_block');

function render_hero_block($attributes) {
    $title = $attributes['title'] ?? '';
    return "<div class='hero'><h1>$title</h1></div>";
}
